import{_ as i,o,c as a,a3 as t}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"3G. Aboriginal Employment Support Officer","description":"","frontmatter":{"title":"3G. Aboriginal Employment Support Officer","eba":"Health Allied & Managers Admin 2021-2025","topics":["schedules","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/schedules/3g-aboriginal-employment-support-officer.md","filePath":"ebas/has-managers-admin/schedules/3g-aboriginal-employment-support-officer.md"}'),n={name:"ebas/has-managers-admin/schedules/3g-aboriginal-employment-support-officer.md"};function r(s,e,l,p,c,m){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="_3g-aboriginal-employment-support-officer" tabindex="-1">3G. Aboriginal Employment Support Officer <a class="header-anchor" href="#_3g-aboriginal-employment-support-officer" aria-label="Permalink to &quot;3G. Aboriginal Employment Support Officer&quot;">​</a></h1><p>Formatting note</p><p>The schedule body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find schedules by their title, number, topic or synonyms.</p><p>```text SUPPORT OFFICER 4. The Role 4.1 An Aboriginal Employment Support Officer will be responsible for promoting the achievement of a two per cent Aboriginal Employment Target and the prioritisation of focus areas set out in the DH Aboriginal Employment Strategy 2016-2021: (a) Profile and Leadership (b) Recruitment (c) Retention (d) Inclusive Workplaces (e) Induction (f) Development</p><ol><li><p>Duties Duties include:</p><p>5.1 Development and/or maintenance of the local Aboriginal Employment Plan which aims to increase the Aboriginal workforce across all areas of the organisation.</p><p>5.2 Promote the focus areas set out in the DH Aboriginal Employment Strategy 2016- 2021 and ensure that these practices are culturally relevant, culturally appropriate while also consistent with local policies and procedures.</p><p>5.3 Networking with the local Aboriginal community, Aboriginal community organisations, high schools, TAFE and University.</p></li><li><p>Qualifications/Experience Required qualifications and experience for this role is as follows:</p><p>6.1 Is an Aboriginal or Torres Strait Islander person, identifies as Aboriginal and is accepted as such by the community in which he/ she lives or has previously lived.</p><p>6.2 Sound knowledge of Aboriginal culture and experience in working with Aboriginal and Torres Strait Islander peoples/ communities and organisations.</p><p>6.3 Relevant tertiary qualifications in Human Resources (or equivalent) or significant experience in Aboriginal Employment, Recruitment and Engagement. ```</p></li></ol>',5)])])}const h=i(n,[["render",r]]);export{d as __pageData,h as default};
